-- Расширяет subscriptions для поддержки T-Bank recurrent payments и soft-cancel grace period.
--
-- Новые поля:
--   - auto_renew (default FALSE, fail-closed): Edge Function явно выставляет true
--     при инсерте подписки, если юзер согласился на Recurrent=Y на чекауте.
--     Дефолт false защищает от случайной активации auto-charge при баге Edge Function.
--   - rebill_id: T-Bank RebillId для авто-списаний через /Charge.
--   - grace_until: обычный nullable timestamptz, заполняется Edge Function при
--     каждом insert/update подписки как `current_period_ends_at + interval '7 days'`.
--     Изначально это поле планировалось как GENERATED STORED, но Postgres отвергает
--     `timestamptz + interval` в stored-выражении (ERROR 42P17: generation expression
--     is not immutable — DST-aware арифметика помечена как STABLE, не IMMUTABLE).
--     TODO: при наличии reliable Edge Function можно добавить BEFORE trigger для
--     автоматического заполнения, если "забыть проставить" станет реальной проблемой.
--
-- Активная подписка = is_current AND now() < coalesce(grace_until, current_period_ends_at).
-- Hook useActiveSubscription на фронте использует эту логику; fallback на
-- current_period_ends_at — для подписок созданных до того как Edge Function научился
-- ставить grace_until.
--
-- COMMENT ON и `if not exists` не используются — backend-truth парсер их не поддерживает.

alter table public.subscriptions
  add column auto_renew boolean not null default false,
  add column rebill_id text,
  add column grace_until timestamptz;

create index idx_subscriptions_rebill_id on public.subscriptions(rebill_id)
  where rebill_id is not null;

create index idx_subscriptions_grace_until on public.subscriptions(grace_until)
  where grace_until is not null;
